const raw  = $input.first().json;
const body = (raw.body !== undefined) ? raw.body : raw;

if (!body.job_id)     throw new Error('Missing job_id');
if (!body.clip_paths) throw new Error('Missing clip_paths from Stage 2');
if (!body.audio_path) throw new Error('Missing audio_path from Stage 2');
if (!body.ass_path)   throw new Error('Missing ass_path from Stage 2');

console.log('Stage 3 start | job:', body.job_id, '| clips:', (body.clip_paths || []).length);
return [{ json: body }];

// ═══════════════════════════════════════════════════════════════
// STAGE 3 — FULL ASSEMBLY PIPELINE
// Applies to each clip:
//   1. Normalize → 1080×1920 9:16
//   2. Ken Burns zoom effect (slow push-in from 110% → 100%)
//   3. xfade transitions alternating: fade ↔ slideleft (the "side change")
//   4. Mix ElevenLabs voice (full volume) + BGM (12% volume)
//   5. Burn karaoke ASS captions (word-by-word yellow highlight)
//   6. Watermark logo top-right (if logo.png present)
//   7. Export H.264 1080×1920 24fps high quality
// ═══════════════════════════════════════════════════════════════
const { execSync } = require('child_process');
const fs           = require('fs');

const data     = $input.first().json;
const jobId    = data.job_id;
const clips    = data.clip_paths || [];        // /data/ffmpeg/input paths (n8n host)
const audioP   = data.audio_path;              // /data/ffmpeg/input/{jobId}_voice.mp3
const assP     = data.ass_path;                // /data/ffmpeg/input/{jobId}_captions.ass
const hlWords  = (data.highlight_keywords || []);
const audioDur = data.audio_duration || 30;
const N        = clips.length;

if (N === 0) throw new Error('No clip_paths received');

const n8nIn   = '/data/ffmpeg/input';
const n8nOut  = '/data/ffmpeg/output';
const contIn  = '/ffmpeg/input';
const contOut = '/ffmpeg/output';

if (!fs.existsSync(n8nOut)) fs.mkdirSync(n8nOut, { recursive: true });

// ── Helper: run docker exec command ──────────────────────────────
function run(cmd, timeoutMs, ignoreErr) {
  try {
    return execSync(cmd, { encoding: 'utf-8', timeout: timeoutMs || 120000 });
  } catch(e) {
    const out = ((e.stdout || '') + (e.stderr || '')).toString();
    if (ignoreErr) { console.warn('WARN: ' + out.slice(-200)); return ''; }
    throw new Error(out.slice(-600));
  }
}

// ── Helper: n8n host path → container path ───────────────────────
function toContPath(p) {
  return p.replace('/data/ffmpeg', '/ffmpeg');
}

// ── STEP 1: Normalize each clip → 1080×1920, 24fps, no audio ─────
console.log('Step 1: Normalising ' + N + ' clips...');
const normPaths = [];
for (let i = 0; i < N; i++) {
  const src  = toContPath(clips[i]);
  const dst  = contIn + '/' + jobId + '_norm' + i + '.mp4';
  const dstH = n8nIn  + '/' + jobId + '_norm' + i + '.mp4';
  run(
    'docker exec qpc_ffmpeg_runner ffmpeg -y' +
    ' -i "' + src + '"' +
    ' -vf "scale=1080:1920:force_original_aspect_ratio=increase,' +
    'crop=1080:1920,setsar=1,fps=24"' +
    ' -c:v libx264 -crf 18 -preset fast -pix_fmt yuv420p -an' +
    ' "' + dst + '" && echo NORM_OK',
    120000
  );
  normPaths.push({ n8n: dstH, cont: dst });
  console.log('  Clip ' + (i+1) + ' normalised');
}

// ── STEP 2: Apply Ken Burns zoom to each normalised clip ──────────
// Each clip slowly zooms from 110% → 100% (push-in feel).
// We scale to 1188×2112 (1080*1.1 × 1920*1.1) then crop back to 1080×1920
// with time-based offset so the crop window shrinks = zoom-in effect.
// Formula: cropX = (1188-1080)/2 * (1 - t/5)  = 54*(1-t/5)
//          cropY = (2112-1920)/2 * (1 - t/5)  = 96*(1-t/5)
// t=0 → crop from (54,96) = zoomed in 110%
// t=5 → crop from (0,0)   = back to 100%  (zoom OUT = reveal)
// Alternate: zoom-in (t=0→crop(0,0), t=5→crop(54,96))
console.log('Step 2: Applying Ken Burns zoom...');
const zoomPaths = [];
for (let i = 0; i < N; i++) {
  const src = normPaths[i].cont;
  const dst = contIn + '/' + jobId + '_zoom' + i + '.mp4';
  const dstH= n8nIn  + '/' + jobId + '_zoom' + i + '.mp4';

  // Alternate zoom direction per clip for visual variety
  // Even clips: zoom-in (start wide, push in)
  // Odd clips:  zoom-out (start tight, pull back)
  const zoomIn = (i % 2 === 0);
  const cropXExpr = zoomIn
    ? '(1188-1080)/2*t/5'       // 0→54 (zoom in)
    : '(1188-1080)/2*(1-t/5)';  // 54→0 (zoom out)
  const cropYExpr = zoomIn
    ? '(2112-1920)/2*t/5'
    : '(2112-1920)/2*(1-t/5)';

  run(
    'docker exec qpc_ffmpeg_runner ffmpeg -y' +
    ' -i "' + src + '"' +
    ' -vf "scale=1188:2112:flags=lanczos,' +
    "crop=1080:1920:'" + cropXExpr + "':'" + cropYExpr + "'," +
    'setsar=1,fade=t=in:st=0:d=0.25,fade=t=out:st=4.75:d=0.25"' +
    ' -c:v libx264 -crf 17 -preset fast -pix_fmt yuv420p -an' +
    ' "' + dst + '" && echo ZOOM_OK',
    180000
  );
  zoomPaths.push({ n8n: dstH, cont: dst });
  console.log('  Clip ' + (i+1) + ' zoom ' + (zoomIn ? 'IN' : 'OUT') + ' done');
}

// ── STEP 3: xfade transitions between clips ───────────────────────
// Alternates: fade (even boundaries) ↔ slideleft (odd boundaries)
// This creates the "side changing effect" the user wants.
// Transition duration: 0.4s
// Each clip is 5s, so offsets: 4.6, 9.2, 13.8, 18.4, 23.0
console.log('Step 3: Concatenating ' + N + ' clips → ' + (N * 5) + 's exact...');

// concat keeps each clip at full 5s → N×5s = 30s exactly
// Dip-to-dark transitions baked into clips via fade-in/out in Step 2
const CLIP_DUR = 5.0;

let xfadePath;

if (N === 1) {
  xfadePath = { n8n: zoomPaths[0].n8n, cont: zoomPaths[0].cont };
} else {
  const inputs       = zoomPaths.map(p => '-i "' + p.cont + '"').join(' ');
  const concatFilter = 'concat=n=' + N + ':v=1:a=0[vout]';
  const concatCont   = contIn + '/' + jobId + '_concat.mp4';
  const concatN8n    = n8nIn  + '/' + jobId + '_concat.mp4';

  run(
    'docker exec qpc_ffmpeg_runner ffmpeg -y ' + inputs +
    ' -filter_complex "' + concatFilter + '"' +
    ' -map "[vout]"' +
    ' -c:v libx264 -crf 17 -preset fast -pix_fmt yuv420p -an' +
    ' "' + concatCont + '" && echo CONCAT_OK',
    300000
  );
  xfadePath = { n8n: concatN8n, cont: concatCont };
  console.log('Concat done: ' + N + ' clips × 5s = ' + (N * CLIP_DUR) + 's');
}

// ── STEP 4: Verify audio + BGM ────────────────────────────────────
console.log('Step 4: Checking audio files...');
const voiceCont = toContPath(audioP);
const hasVoice  = run('docker exec qpc_ffmpeg_runner test -f "' + voiceCont + '" && echo OK', 10000, true).includes('OK');

// BGM: look in /ffmpeg/config/bgm/ — pick a warm nature/ambient track
const bgmCandidates = ['NatureAmbient', 'Odyssey', 'Arcane', 'Apprehension', 'Anamalie'];
let bgmFile = null;
for (const track of bgmCandidates) {
  const p = '/ffmpeg/config/bgm/' + track + '.mp3';
  if (run('docker exec qpc_ffmpeg_runner test -f "' + p + '" && echo OK', 5000, true).includes('OK')) {
    bgmFile = p;
    console.log('BGM selected: ' + track);
    break;
  }
}

// Trim BGM to video duration + fade
let bgmTrimmed = null;
if (bgmFile) {
  const totalDur  = audioDur; // match BGM to full voice duration
  const bgmDst    = contIn + '/' + jobId + '_bgm.mp3';
  const fadeSt    = Math.max(0, totalDur - 1.5).toFixed(2);
  run(
    'docker exec qpc_ffmpeg_runner ffmpeg -y -i "' + bgmFile + '"' +
    ' -t ' + totalDur.toFixed(2) +
    ' -af "afade=t=in:st=0:d=1.0,afade=t=out:st=' + fadeSt + ':d=1.5,volume=0.12"' +
    ' -acodec libmp3lame -ab 128k "' + bgmDst + '" && echo BGM_OK',
    60000, true
  );
  bgmTrimmed = bgmDst;
  console.log('BGM trimmed and ready');
}

// ── STEP 5: ASS captions path ─────────────────────────────────────
const assCont = toContPath(assP);
const hasASS  = run('docker exec qpc_ffmpeg_runner test -f "' + assCont + '" && echo OK', 5000, true).includes('OK');
console.log('ASS captions: ' + (hasASS ? 'found' : 'MISSING – captions skipped'));

// ── STEP 6: Logo watermark ────────────────────────────────────────
const logoPath  = '/ffmpeg/config/icon/logo.png';
const hasLogo   = run('docker exec qpc_ffmpeg_runner test -f "' + logoPath + '" && echo OK', 5000, true).includes('OK');

// ── STEP 7: Build final FFmpeg command ───────────────────────────
// Input list
const inp = ['-i "' + xfadePath.cont + '"'];
if (hasVoice)   inp.push('-i "' + voiceCont + '"');
if (bgmTrimmed) inp.push('-i "' + bgmTrimmed + '"');
if (hasLogo)    inp.push('-i "' + logoPath + '"');

const voiceIdx = hasVoice   ? 1 : -1;
const bgmIdx   = bgmTrimmed ? (hasVoice ? 2 : 1) : -1;
const logoIdx  = hasLogo    ? inp.length - 1 : -1;

// Video filter chain
let vFilters = [];
let vLabel   = '0:v';
let lbl      = 0;

// Logo overlay: top-right, 80px wide, 20px margin
if (hasLogo) {
  vFilters.push(
    '[' + logoIdx + ':v]scale=80:-1[logo_s];' +
    '[' + vLabel  + '][logo_s]overlay=x=W-w-20:y=20:format=auto[vl' + lbl + ']'
  );
  vLabel = 'vl' + lbl; lbl++;
}

// Burn ASS captions
if (hasASS) {
  vFilters.push('[' + vLabel + "]subtitles=filename='" + assCont + "'[vv" + lbl + ']');
  vLabel = 'vv' + lbl; lbl++;
}

// Final video label
const outVLabel = lbl > 0 ? '[' + vLabel + ']' : '[0:v]';

// Audio mix: voice at 100% + BGM at 12%
let audioMap = '-an';
let aFilterStr = '';

// Fade to black at end (covers both padded and non-padded cases)
const _fadeStart = Math.max(0, audioDur - 1.5).toFixed(2);
vFilters.push('[' + vLabel + ']fade=t=out:st=' + _fadeStart + ':d=1.5:color=black[vfadeout' + lbl + ']');
vLabel = 'vfadeout' + lbl; lbl++;

// Audio fade-out on voice
const _audioFadeStart = Math.max(0, audioDur - 1.2).toFixed(2);
if (hasVoice && bgmTrimmed) {
  aFilterStr = ';[' + voiceIdx + ':a]volume=0.75,afade=t=out:st=' + _audioFadeStart + ':d=1.2[nar];[' + bgmIdx + ':a]volume=1.0[bgm];[nar][bgm]amix=inputs=2:duration=first:dropout_transition=2[aout]';
  audioMap   = '-map "[aout]"';
} else if (hasVoice) {
  aFilterStr = ';[' + voiceIdx + ':a]volume=0.75,afade=t=out:st=' + _audioFadeStart + ':d=1.2[aout]';
  audioMap   = '-map "[aout]"';
} else if (bgmTrimmed) {
  aFilterStr = ';[' + bgmIdx + ':a]volume=1.0,afade=t=out:st=' + _audioFadeStart + ':d=1.2[aout]';
  audioMap   = '-map "[aout]"';
}

const fullFilter = vFilters.join(';') + aFilterStr;
const finalCont  = contOut + '/' + jobId + '_final.mp4';
const finalN8n   = n8nOut  + '/' + jobId + '_final.mp4';
const totalSec   = Math.ceil(audioDur) + 2;

const filterArg = fullFilter
  ? ' -filter_complex "' + fullFilter + '" -map "[' + vLabel + ']" ' + audioMap
  : ' -map "0:v" ' + audioMap;

const finalCmd =
  'docker exec qpc_ffmpeg_runner ffmpeg -y ' + inp.join(' ') +
  filterArg +
  ' -c:v libx264 -crf 17 -preset fast -pix_fmt yuv420p -movflags +faststart' +
  (audioMap !== '-an' ? ' -c:a aac -b:a 192k' : '') +
  ' -t ' + totalSec +
  ' "' + finalCont + '" && echo FINAL_OK';

console.log('Step 7: Final render...');
const renderOut = run(finalCmd, 900000);
if (!renderOut.includes('FINAL_OK')) throw new Error('Final render failed: ' + renderOut.slice(-500));
if (!fs.existsSync(finalN8n)) throw new Error('Final file not found: ' + finalN8n);

const stats     = fs.statSync(finalN8n);
const fileMB    = (stats.size / 1048576).toFixed(1);
const renderSec = Math.round((Date.now() - (data.start_time || Date.now())) / 1000);
console.log('Final video: ' + fileMB + ' MB | render time: ' + renderSec + 's');

return [{ json: {
  ...data,
  final_video_path: finalN8n,
  output_filename:  jobId + '_final.mp4',
  file_size_mb:     parseFloat(fileMB),
  render_time_sec:  renderSec,
  clips_used:       N,
  has_voice:        hasVoice,
  has_bgm:          !!bgmTrimmed,
  has_captions:     hasASS
}}];

const fs   = require('fs');
const data = $input.first().json;
const path = data.final_video_path;

if (!fs.existsSync(path)) throw new Error('Final video not found: ' + path);

const b64 = fs.readFileSync(path).toString('base64');
return [{
  json: data,
  binary: {
    data: {
      data:          b64,
      mimeType:      'video/mp4',
      fileName:      data.output_filename,
      fileExtension: 'mp4'
    }
  }
}];

const driveNode    = $('Upload to Google Drive').first().json;
const assembleData = $('Assemble Final Video').first().json;
const fileId       = driveNode.id;
const videoUrl     = 'https://drive.google.com/file/d/' + fileId + '/view';
const downloadUrl  = 'https://drive.usercontent.google.com/download?id=' + fileId + '&export=download';

console.log('Stage 3 complete: ' + assembleData.job_id + ' → ' + videoUrl);

return [{ json: {
  job_id:          assembleData.job_id,
  topic:           assembleData.topic,
  title:           assembleData.title,
  hashtags:        assembleData.hashtags,
  narration:       assembleData.narration,
  cta:             assembleData.cta,
  video_url:       videoUrl,
  download_url:    downloadUrl,
  drive_file_id:   fileId,
  file_size_mb:    assembleData.file_size_mb,
  render_time_sec: assembleData.render_time_sec,
  clips_used:      assembleData.clips_used,
  has_voice:       assembleData.has_voice,
  has_bgm:         assembleData.has_bgm,
  has_captions:    assembleData.has_captions,
  sheet_row:       assembleData.sheet_row
}}];

// Clean up temp files after successful completion
const fs      = require('fs');
const data    = $('Stage 3 Done').first().json;
const assembl = $('Assemble Final Video').first().json;
const jobId   = assembl.job_id;
const n8nIn   = '/data/ffmpeg/input';

const patterns = [
  '_norm', '_zoom', '_xfade', '_bgm', '_captions'
];

let removed = 0;
const files  = fs.readdirSync(n8nIn);
for (const f of files) {
  if (!f.startsWith(jobId)) continue;
  const shouldDelete = patterns.some(p => f.includes(p));
  if (shouldDelete) {
    try { fs.unlinkSync(n8nIn + '/' + f); removed++; } catch(e) {}
  }
}
console.log('Cleaned up ' + removed + ' temp files for job ' + jobId);

return [{ json: {
  ...data,
  cleanup_done: true,
  temp_files_removed: removed
}}];
